impl RequireClaim {
    /// Each claim line in this group's body (parsed as [`Field`]s:
    /// `subject: predicate`). Direct children only -- claims nested
    /// inside a `forall <var> in <domain>:` block are NOT included
    /// here; see [`RequireClaim::sweeps`] and
    /// [`RequireClaim::all_claims`] (WO-68).
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    pub fn claims(&self) -> Vec<Field> {
        self.syntax.children().filter_map(Field::cast).collect()
    }

    /// Each `forall <var> in <domain>:` BLOCK claim directly in this
    /// group's body (WO-68).
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    // frob:waive TEST001 reason="thin CST accessor exercised transitively by every parser/lowering test that walks this node kind; no dedicated unit test isolates the accessor itself"
    pub fn sweeps(&self) -> Vec<ForallSweepClaim> {
        self.syntax
            .children()
            .filter_map(ForallSweepClaim::cast)
            .collect()
    }

    /// Every claim in this group, direct or nested inside a `forall
    /// <var> in <domain>:` block, paired with the sweep it is under
    /// (`None` for a direct claim) -- source order, direct claims
    /// interleaved with each sweep's claims in the sweep's own
    /// position (WO-68: the single accessor the lowering pass uses so
    /// no claim group can silently drop a nested named claim again).
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    // frob:waive TEST001 reason="thin CST accessor exercised transitively by every parser/lowering test that walks this node kind; no dedicated unit test isolates the accessor itself"
    pub fn all_claims(&self) -> Vec<(Field, Option<ForallSweepClaim>)> {
        let mut out = Vec::new();
        for child in self.syntax.children() {
            if let Some(field) = Field::cast(child.clone()) {
                out.push((field, None));
            } else if let Some(sweep) = ForallSweepClaim::cast(child) {
                for field in sweep.claims() {
                    out.push((field, Some(sweep.clone())));
                }
            }
        }
        out
    }

    /// Each `compute <name>: ...` claim line in this group's body
    /// (WO-33 D98).
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    // frob:waive TEST002 reason="rust collector fails fast on lib-less fuzz/ crate, killing test-evidence collection repo-wide; binding+tests are real, see FROBLEMS 2026-07-18"
    pub fn compute_claims(&self) -> Vec<ComputeField> {
        self.syntax
            .children()
            .filter_map(ComputeField::cast)
            .collect()
    }
}

impl ComputeField {
    /// The produced field's name token text (dotted paths joined with
    /// `.`), skipping the leading `compute` word (whole-node-text +
    /// split approach, mirroring [`ComputeField::predicate_text`]).
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    pub fn name(&self) -> String {
        let full = self.syntax.text().to_string();
        let after_compute = full
            .trim_start()
            .strip_prefix("compute")
            .unwrap_or(full.trim_start())
            .trim_start();
        match after_compute.split_once(':') {
            Some((name, _)) => name.trim().to_string(),
            None => String::new(),
        }
    }

    /// The field's value node (see [`Field::value`]): the `<quantity
    /// kind>` path; the `over <index domain>` tail rides the same
    /// `OpaqueIsland` sweep as any other unmodeled tail.
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    pub fn value(&self) -> Option<SyntaxNode> {
        first_value_child(&self.syntax)
    }

    /// The full source text after the `:` (quantity kind + `over`
    /// clause, verbatim), for the lowering pass to pattern-match the
    /// `over <zone set ref>` / `over <var> in <interval>` shape without
    /// a dedicated sub-grammar (mirrors `full_predicate_text` in
    /// `regolith-lower::claims`, which uses the same whole-node-text +
    /// split-on-`:` approach).
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    // frob:waive TEST002 reason="rust collector fails fast on lib-less fuzz/ crate, killing test-evidence collection repo-wide; binding+tests are real, see FROBLEMS 2026-07-18"
    pub fn predicate_text(&self) -> String {
        let full = self.syntax.text().to_string();
        match full.split_once(':') {
            Some((_, rest)) => rest.trim().to_string(),
            None => String::new(),
        }
    }
}

impl BinExpr {
    /// The left operand.
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    pub fn lhs(&self) -> Option<SyntaxNode> {
        self.syntax.children().next()
    }

    /// The right operand.
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    pub fn rhs(&self) -> Option<SyntaxNode> {
        self.syntax.children().nth(1)
    }
}

impl QuantityLit {
    /// The literal's unit spelling (the `Ident` token immediately
    /// after the number).
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    // frob:waive TEST001 reason="thin CST accessor exercised transitively by every parser/lowering test that walks this node kind; no dedicated unit test isolates the accessor itself"
    pub fn unit_text(&self) -> Option<String> {
        self.syntax
            .children_with_tokens()
            .filter_map(rowan::NodeOrToken::into_token)
            .find(|t| t.kind() == SyntaxKind::Ident)
            .map(|t| t.text().to_string())
    }
}

/// Join a `name`/`ctor` statement's leading `Ident (. Ident)*` name
/// tokens with `.` (the accessor both [`Field::name`] and
/// [`CtorStmt::name`] share).
fn name_path_text(node: &SyntaxNode) -> String {
    node.children_with_tokens()
        .filter_map(rowan::NodeOrToken::into_token)
        .take_while(|t| matches!(t.kind(), SyntaxKind::Ident | SyntaxKind::Dot))
        .map(|t| t.text().to_string())
        .collect()
}

/// The first child node of a `Field`/`CtorStmt` that is not the
/// trailing lossless-sweep `OpaqueIsland` (the recognized value, when
/// the grammar classified one).
fn first_value_child(node: &SyntaxNode) -> Option<SyntaxNode> {
    node.children()
        .find(|c| c.kind() != SyntaxKind::OpaqueIsland)
}

impl Decl {
    /// The declaration keyword (`part`, `interface`, `system`, ...).
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    // frob:waive TEST002 reason="rust collector fails fast on lib-less fuzz/ crate, killing test-evidence collection repo-wide; binding+tests are real, see FROBLEMS 2026-07-18"
    pub fn kind_keyword(&self) -> Option<SyntaxKind> {
        self.syntax
            .children_with_tokens()
            .filter_map(rowan::NodeOrToken::into_token)
            .map(|t| t.kind())
            .find(|k| !k.is_trivia())
    }

    /// The declaration's own name: the first `Ident` token in the
    /// header line (before any generic-parameter `<...>` list, which
    /// this WO does not further decompose -- see the report note).
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    pub fn name(&self) -> Option<String> {
        self.syntax
            .children_with_tokens()
            .filter_map(rowan::NodeOrToken::into_token)
            .find(|t| t.kind() == SyntaxKind::Ident)
            .map(|t| t.text().to_string())
    }

    /// The declaration's structured statements (fields, ctor
    /// statements, `then`/`require`/`budget`/`waive`/`policy`/`locked`
    /// blocks); domain-specific statements remain opaque and are
    /// omitted here (call [`AstNode::syntax`] and filter
    /// `OpaqueIsland` children directly to see everything).
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    // frob:waive TEST002 reason="rust collector fails fast on lib-less fuzz/ crate, killing test-evidence collection repo-wide; binding+tests are real, see FROBLEMS 2026-07-18"
    pub fn fields(&self) -> Vec<Field> {
        self.syntax.children().filter_map(Field::cast).collect()
    }

    /// The declaration's `require <Group>:` claim groups.
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    pub fn claims(&self) -> Vec<RequireClaim> {
        self.syntax
            .children()
            .filter_map(RequireClaim::cast)
            .collect()
    }

    /// The declaration's structured `budget ...:` statements.
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    // frob:waive TEST001 reason="thin CST accessor exercised transitively by every parser/lowering test that walks this node kind; no dedicated unit test isolates the accessor itself"
    pub fn budgets(&self) -> Vec<BudgetStmt> {
        self.syntax
            .children()
            .filter_map(BudgetStmt::cast)
            .collect()
    }

    /// Every `waive ...:` block anywhere in the declaration body (top
    /// level or nested inside a `then` scope): the rung-7 concessions
    /// this subject declares (regolith/12 sec. 3).
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    // frob:waive TEST002 reason="rust collector fails fast on lib-less fuzz/ crate, killing test-evidence collection repo-wide; binding+tests are real, see FROBLEMS 2026-07-18"
    pub fn waivers(&self) -> Vec<WaiveBlock> {
        self.syntax
            .descendants()
            .filter_map(WaiveBlock::cast)
            .collect()
    }

    /// True when this is a `process` module declaration (hematite/04
    /// sec. 2A) -- the leading word is the contextual `process` ident.
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    // frob:waive TEST002 reason="rust collector fails fast on lib-less fuzz/ crate, killing test-evidence collection repo-wide; binding+tests are real, see FROBLEMS 2026-07-18"
    pub fn is_process(&self) -> bool {
        self.syntax
            .children_with_tokens()
            .filter_map(rowan::NodeOrToken::into_token)
            .find(|t| !t.kind().is_trivia())
            .is_some_and(|t| t.kind() == SyntaxKind::Ident && t.text() == "process")
    }

    /// A process decl's own name (`process press_brake_shop:` ->
    /// `press_brake_shop`; a dotted registry path,
    /// `process std.sheet_metal:`, yields `std.sheet_metal` whole --
    /// packs are registry content per regolith/11, so namespaced pack
    /// names are first-class). `None` for non-process decls
    /// ([`Decl::name`] keeps its first-ident behavior, which lowering
    /// subjects rely on).
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    // frob:waive TEST002 reason="rust collector fails fast on lib-less fuzz/ crate, killing test-evidence collection repo-wide; binding+tests are real, see FROBLEMS 2026-07-18"
    pub fn process_name(&self) -> Option<String> {
        if !self.is_process() {
            return None;
        }
        // The contiguous Ident/Dot run after the leading `process`
        // word (non-trivia tokens other than Ident/Dot end the name).
        let mut out = String::new();
        for token in self
            .syntax
            .children_with_tokens()
            .filter_map(rowan::NodeOrToken::into_token)
            .filter(|t| !t.kind().is_trivia())
            .skip(1)
        {
            match token.kind() {
                SyntaxKind::Ident | SyntaxKind::Dot => out.push_str(token.text()),
                _ => break,
            }
        }
        (!out.is_empty()).then_some(out)
    }

    /// A process decl's `capability:` table, if declared
    /// (hematite/02 sec. 10).
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    pub fn capability(&self) -> Option<CapabilityBlock> {
        self.syntax.children().find_map(CapabilityBlock::cast)
    }

    /// A process decl's rule-pack blocks (`dfm:`/`drc:`/`erc:`), in
    /// source order.
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    // frob:waive TEST002 reason="rust collector fails fast on lib-less fuzz/ crate, killing test-evidence collection repo-wide; binding+tests are real, see FROBLEMS 2026-07-18"
    pub fn rule_packs(&self) -> Vec<RulePackBlock> {
        self.syntax
            .children()
            .filter_map(RulePackBlock::cast)
            .collect()
    }
}

impl MediumDecl {
    /// The medium's name: the first `Ident` after the leading contextual
    /// `medium` word (`medium ShopAir: gas` -> `ShopAir`).
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    pub fn name(&self) -> Option<String> {
        header_ident_after_keyword(&self.syntax)
    }

    /// The phase word (`liquid`/`gas`): the `Ident` after the header
    /// `:` (fluorite/02 sec. 1).
    #[must_use]
    // frob:doc docs/modules/regolith-syntax.md#ast
    // frob:waive TEST002 reason="rust collector fails fast on lib-less fuzz/ crate, killing test-evidence collection repo-wide; binding+tests are real, see FROBLEMS 2026-07-18"
    pub fn phase(&self) -> Option<String> {
        let mut toks = self
            .syntax
            .children_with_tokens()
            .filter_map(rowan::NodeOrToken::into_token)
            .skip_while(|t| t.kind() != SyntaxKind::Colon);
        toks.next(); // the `:` itself
        toks.find(|t| t.kind() == SyntaxKind::Ident)
            .map(|t| t.text().to_string())
    }
}

