#[cfg(test)]
mod tests {
    use super::{AstNode, Decl, File};
    use crate::syntax_kind::SyntaxKind;

    #[test]
    // frob:tests crates/regolith-syntax/src/ast.rs::MediumDecl.phase kind="unit"
    // frob:tests crates/regolith-syntax/src/ast.rs::File.decls kind="unit"
    // frob:tests crates/regolith-syntax/src/ast.rs::File.mediums kind="unit"
    // frob:tests crates/regolith-syntax/src/ast.rs::File.fluid_requires kind="unit"
    fn fluorite_surface_exposes_typed_medium_flownet_and_require() {
        // fluorite/02 sec. 1/4/6: medium + flownet(edges/states) +
        // top-level require, all as typed CST nodes with lossless
        // round-trip (WO-31 deliverable 2).
        let src = "import std.fluorite (Pipe, Valve)\n\
                   medium Water: liquid\n\
                   \x20\x20\x20\x20props: registry(freshwater_25c)\n\
                   flownet Loop(medium=Water):\n\
                   \x20\x20\x20\x20reference: ambient(101kPa, 298K)\n\
                   \x20\x20\x20\x20nodes: a, b\n\
                   \x20\x20\x20\x20edges:\n\
                   \x20\x20\x20\x20\x20\x20\x20\x20pipe: Pipe(from=line.run) (a -> b)\n\
                   \x20\x20\x20\x20states:\n\
                   \x20\x20\x20\x20\x20\x20\x20\x20state mode in {idle, run}\n\
                   require Margin:\n\
                   \x20\x20\x20\x20margin: fluids.dp(a -> b) <= 15kPa\n";
        let file_path = camino::Utf8PathBuf::from("t.fluo");
        let parse = crate::parser::parse(src, &file_path);
        assert!(parse.diagnostics().is_empty(), "{:?}", parse.diagnostics());
        // Lossless round-trip (the AD-3 coverage invariant).
        assert_eq!(parse.syntax().text().to_string(), src);
        let file = File::cast(parse.syntax()).expect("root is File");

        let medium = file.mediums().into_iter().next().expect("one medium");
        assert_eq!(medium.name().as_deref(), Some("Water"));
        assert_eq!(medium.phase().as_deref(), Some("liquid"));

        let flownet = file.flownets().into_iter().next().expect("one flownet");
        assert_eq!(flownet.name().as_deref(), Some("Loop"));
        let edges = flownet.edges().expect("edges block");
        let edge = edges.edges().into_iter().next().expect("one edge");
        assert_eq!(edge.name(), "pipe");
        assert!(edge.value().is_some(), "edge constructor is a typed value");
        let states = flownet.states().expect("states block");
        assert_eq!(states.states().len(), 1);

        let req = file
            .fluid_requires()
            .into_iter()
            .next()
            .expect("one require");
        assert_eq!(req.claims().len(), 1);
        // A top-level require is NOT a plain Decl.
        assert!(file.decls().is_empty(), "no generic Decls in this file");
    }

    #[test]
    fn can_cast_matches_kind() {
        assert!(File::can_cast(SyntaxKind::File));
        assert!(!File::can_cast(SyntaxKind::Decl));
        assert!(Decl::can_cast(SyntaxKind::Decl));
    }

    #[test]
    fn file_exposes_imports_and_decls_in_source_order() {
        let src = "import a.b\npart wall:\n    x: 1\nprofile p:\n    y: 2\n";
        let file_path = camino::Utf8PathBuf::from("t.hema");
        let parse = crate::parser::parse(src, &file_path);
        let file = File::cast(parse.syntax()).expect("root is File");
        assert_eq!(file.imports().len(), 1);
        assert_eq!(file.decls().len(), 2);
    }

    #[test]
    // frob:tests crates/regolith-syntax/src/ast.rs::WaiveBlock.expires kind="unit"
    // frob:tests crates/regolith-syntax/src/ast.rs::WaiveBlock.has_evidence kind="unit"
    // frob:tests crates/regolith-syntax/src/ast.rs::Decl.waivers kind="unit"
    fn waive_block_exposes_target_scope_basis_and_evidence() {
        let src = "part p:\n    waive dfm(min_web) on milled.wall:\n        basis: \"qual unit VR-081\"\n        by test(vr081)\n        expires: 2027-01-01\n";
        let file_path = camino::Utf8PathBuf::from("t.hema");
        let parse = crate::parser::parse(src, &file_path);
        let file = File::cast(parse.syntax()).expect("root is File");
        let decl = file.decls().into_iter().next().expect("one decl");
        let wb = decl.waivers().into_iter().next().expect("one waiver");
        assert_eq!(wb.target(), "dfm(min_web)");
        assert_eq!(wb.scope().as_deref(), Some("milled.wall"));
        assert_eq!(wb.basis().as_deref(), Some("qual unit VR-081"));
        assert!(wb.has_evidence(), "the `by` clause is evidence");
        assert_eq!(wb.evidence().as_deref(), Some("test(vr081)"));
        assert_eq!(wb.expires().as_deref(), Some("2027-01-01"));
    }

    #[test]
    fn an_unscoped_basis_less_waiver_reports_none() {
        let src = "part p:\n    waive Group.claim:\n        note: 1\n";
        let file_path = camino::Utf8PathBuf::from("t.hema");
        let parse = crate::parser::parse(src, &file_path);
        let file = File::cast(parse.syntax()).expect("root is File");
        let decl = file.decls().into_iter().next().expect("one decl");
        let wb = decl.waivers().into_iter().next().expect("one waiver");
        assert_eq!(wb.target(), "Group.claim");
        assert_eq!(wb.scope(), None);
        assert_eq!(wb.basis(), None);
        assert!(!wb.has_evidence());
    }

    #[test]
    // frob:tests crates/regolith-syntax/src/ast.rs::SensePair.from_name kind="unit"
    // frob:tests crates/regolith-syntax/src/ast.rs::SensePair.to_name kind="unit"
    // frob:tests crates/regolith-syntax/src/ast.rs::DomainSet.items kind="unit"
    fn flownet_edge_sense_and_state_domain_are_readable() {
        let src = "flownet Loop(medium=Water):\n\
                   \x20\x20\x20\x20reference: tank_in\n\
                   \x20\x20\x20\x20nodes: tank_in, tank_out\n\
                   \x20\x20\x20\x20edges:\n\
                   \x20\x20\x20\x20\x20\x20\x20\x20pump: Pump(from=p.run) (tank_in -> tank_out)\n\
                   \x20\x20\x20\x20states:\n\
                   \x20\x20\x20\x20\x20\x20\x20\x20pump.state in {off, on}\n\
                   \x20\x20\x20\x20\x20\x20\x20\x20state mode in {idle, active}\n";
        let file_path = camino::Utf8PathBuf::from("t.fluo");
        let parse = crate::parser::parse(src, &file_path);
        let file = File::cast(parse.syntax()).expect("root is File");
        let net = file.flownets().into_iter().next().expect("one flownet");

        let edge = net.edges().expect("edges block").edges().remove(0);
        let sense = edge.sense().expect("sense pair");
        assert_eq!(sense.from_name().as_deref(), Some("tank_in"));
        assert_eq!(sense.to_name().as_deref(), Some("tank_out"));

        let states = net.states().expect("states block").states();
        let domains: Vec<Vec<String>> = states
            .iter()
            .map(|s| s.domain().expect("typed domain").items())
            .collect();
        assert_eq!(domains[0], vec!["off".to_string(), "on".to_string()]);
        assert_eq!(domains[1], vec!["idle".to_string(), "active".to_string()]);
    }

    /// fluorite/02 sec. 2: `interface FluidPort<...>` reuses the
    /// existing generic-interface machinery unmodified; `through`/
    /// `across` flow-role markers are ordinary bareword field values
    /// (no new keyword), so the header, the `flow:`/`roles:` blocks,
    /// and every single-name field line parse cleanly with no parse
    /// diagnostics.
    #[test]
    // frob:tests crates/regolith-syntax/src/ast.rs::Decl.kind_keyword kind="unit"
    fn fluid_port_interface_reuses_existing_machinery() {
        let src = "interface FluidPort<m: medium, dia: length>:\n\
                   \x20\x20\x20\x20flow:\n\
                   \x20\x20\x20\x20\x20\x20\x20\x20mdot: through\n\
                   \x20\x20\x20\x20roles:\n\
                   \x20\x20\x20\x20\x20\x20\x20\x20bore: circular(dia)\n";
        let file_path = camino::Utf8PathBuf::from("t.fluo");
        let parse = crate::parser::parse(src, &file_path);
        assert_eq!(parse.syntax().text().to_string(), src);
        assert!(parse.diagnostics().is_empty(), "{:?}", parse.diagnostics());
        let file = File::cast(parse.syntax()).expect("root is File");
        let decl = file.decls().into_iter().next().expect("one decl");
        assert_eq!(decl.kind_keyword(), Some(SyntaxKind::InterfaceKw));
    }
}
